void Try(int k)
{
    <Build S_k as the set to consist of candidates
    for the k^th component of solution>;
    for y ∈ S_k   // Each candidate y of S_k
    {
        a_k = y;
        if (k == n) then <Record (a_1, a_2, ..., a_k)
        as a complete solution >;
        else Try(k+1);
             Return the variables to their old states;
    }
}
